const items = $input.all();
const groupMap   = {};
const groupOrder = [];

for (const item of items) {
  const {
    group_key, group_label, entity_type,
    sub_key, sub_field, display_name,
    total_count, browse_count, parent_key
  } = item.json;

  if (!groupMap[group_key]) {
    groupMap[group_key] = {
      group_key, group_label,
      total_count: 0, browse_count: 0,
      sub_types: []
    };
    groupOrder.push(group_key);
  }

  const g = groupMap[group_key];

  if (!parent_key) {
    // Normal sub_type — add to group, accumulate group totals
    g.total_count  += Number(total_count);
    g.browse_count += Number(browse_count);
    const entry = {
      entity_type,
      sub_key:     sub_key   || null,
      sub_field:   sub_field || null,
      display_name,
      total_count:  Number(total_count),
      browse_count: Number(browse_count)
    };
    // Pre-attach children array for entries that will have children
    // (identified by sub_key matching a known parent key)
    entry._childrenHolder = sub_key || null;
    g.sub_types.push(entry);
  } else {
    // Sub-sub-type — find parent sub_type by its sub_key matching parent_key
    const parent = g.sub_types.find(st => st._childrenHolder === parent_key);
    if (parent) {
      if (!parent.children) parent.children = [];
      parent.children.push({
        entity_type,
        sub_key:     sub_key   || null,
        sub_field:   sub_field || null,
        display_name,
        total_count:  Number(total_count),
        browse_count: Number(browse_count)
      });
    }
  }
}

// Clean up internal marker
for (const g of Object.values(groupMap)) {
  for (const st of g.sub_types) {
    delete st._childrenHolder;
  }
}

return [{ json: { groups: groupOrder.map(k => groupMap[k]) } }];
